import os
import datetime
from functools import wraps

import jwt
from flask import Flask, request, jsonify

app = Flask(__name__)

# Configuration
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your_super_secret_key')
app.config['JWT_EXPIRATION_SECONDS'] = 3600  # Token valid for 1 hour

# In-memory user store (for demonstration purposes)
# In a real application, this would be a database
users = {
    'alice': {'password': 'password123', 'roles': ['user']},
    'bob': {'password': 'password456', 'roles': ['admin', 'user']}
}

def create_token(user_id, roles):
    payload = {
        'exp': datetime.datetime.utcnow() + datetime.timedelta(seconds=app.config['JWT_EXPIRATION_SECONDS']),
        'iat': datetime.datetime.utcnow(),
        'sub': user_id,
        'roles': roles
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')

def decode_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return {'error': 'Token has expired'}
    except jwt.InvalidTokenError:
        return {'error': 'Invalid token'}

def jwt_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header:
            return jsonify({'message': 'Authorization header is missing'}), 401

        try:
            token_type, token = auth_header.split(None, 1)
            if token_type.lower() != 'bearer':
                raise ValueError('Invalid token type. Must be Bearer.')
        except ValueError as e:
            return jsonify({'message': str(e) or 'Invalid Authorization header format'}), 401

        payload = decode_token(token)
        if 'error' in payload:
            return jsonify({'message': payload['error']}), 401

        request.current_user = payload['sub']
        request.current_user_roles = payload.get('roles', [])
        return f(*args, **kwargs)
    return decorated_function

def role_required(roles):
    def decorator(f):
        @wraps(f)
        @jwt_required
        def decorated_function(*args, **kwargs):
            if not any(role in request.current_user_roles for role in roles):
                return jsonify({'message': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated_function
    return decorator


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')

    user = users.get(username)
    if user and user['password'] == password:
        token = create_token(username, user['roles'])
        return jsonify({'token': token}), 200
    else:
        return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
@jwt_required
def protected_route():
    return jsonify({
        'message': f'Hello, {request.current_user}! This is a protected route.',
        'user_roles': request.current_user_roles
    })

@app.route('/admin-only', methods=['GET'])
@role_required(['admin'])
def admin_only_route():
    return jsonify({
        'message': f'Welcome, Admin {request.current_user}! You have access to admin resources.',
        'user_roles': request.current_user_roles
    })

@app.route('/user-or-admin', methods=['GET'])
@role_required(['user', 'admin'])
def user_or_admin_route():
    return jsonify({
        'message': f'Hello, {request.current_user}! This route is for users or admins.',
        'user_roles': request.current_user_roles
    })

if __name__ == '__main__':
    app.run(debug=True)